// ============================================
// BOLIGFLOW CSV EXPORT
// Claude: Modify data extraction and row mapping
// to match the user's request.
// ============================================

const response = $input.all()[0].json;
if (response.errors) {
  throw new Error('GraphQL error: ' + response.errors.map(e => e.message).join(', '));
}

// --- DATA EXTRACTION (modify query path as needed) ---
const items = response.data?.leaseAgreements?.data || [];

// --- MAP TO FLAT ROWS (change columns to match the data) ---
const rows = items.map(item => ({
  Adresse: item.lease?.fullAddress || '',
  Status: item.status || '',
  Startdato: item.startDate || '',
  Slutdato: item.endDate || ''
}));

return rows.map(row => ({ json: row }));
